mapper.select:
SELECT cx.maChuyen, cx.tinhTrangChuyen, cx.ngayGioKhoiHanh, cx.ngayGioDen, cx.chiPhiVanHanh, cx.tiLeThuLao, cx.maXe, cx.maMua, cx.maTuyen,
x.bienSo, cx.maTuyen,
gv.giaVe as gv_giaVe, gv.maTuyen, gv.maMua, gv.ngayBatDau as gv_ngayBatDau, gv.ngayKetThuc as gv_ngayKetThuc,
m.tenMua,
td.maTuyen, td.diemKhoiHanh, td.diemDen, td.khoangCach, ltd.luongCoBan AS ltd_luongCoBan, ltd.maLuongTuyen AS ltd_maLuongTuyen FROM ChuyenXe cx JOIN Xe x ON cx.maXe = x.maXe JOIN GiaVe gv ON cx.maTuyen = gv.maTuyen AND cx.maMua = gv.maMua AND cx.maGiaVe = gv.maGiaVe JOIN TuyenDuong td ON cx.maTuyen = td.maTuyen JOIN LuongTuyenDuong ltd ON td.maLuongTuyen = ltd.maLuongTuyen JOIN Mua m ON gv.maMua = m.maMua where 1 = 1
AND DATE(cx.ngayGioKhoiHanh) >= #{khoiHanhTuNgay}
AND DATE(cx.ngayGioKhoiHanh) <= #{khoiHanhDenNgay}
AND td.diemKhoiHanh LIKE CONCAT('%', #{diemKhoiHanh}, '%')
AND td.diemDen LIKE CONCAT('%', #{diemDen}, '%')
AND cx.tinhTrangChuyen = #{tinhTrangChuyen}
order by cx.ngayGioKhoiHanh desc
LIMIT #{limit} OFFSET #{offset}

SELECT count(*) FROM ChuyenXe cx JOIN Xe x ON cx.maXe = x.maXe JOIN GiaVe gv ON cx.maTuyen = gv.maTuyen AND cx.maMua = gv.maMua AND cx.maGiaVe = gv.maGiaVe JOIN TuyenDuong td ON cx.maTuyen = td.maTuyen JOIN LuongTuyenDuong ltd ON td.maLuongTuyen = ltd.maLuongTuyen JOIN Mua m ON gv.maMua = m.maMua where 1 = 1
AND DATE(cx.ngayGioKhoiHanh) >= #{khoiHanhTuNgay}
AND DATE(cx.ngayGioKhoiHanh) <= #{khoiHanhDenNgay}
AND td.diemKhoiHanh LIKE CONCAT('%', #{diemKhoiHanh}, '%')
AND td.diemDen LIKE CONCAT('%', #{diemDen}, '%')
AND cx.tinhTrangChuyen = #{tinhTrangChuyen}

mapper.update:
UPDATE ChuyenXe
SET tinhTrangChuyen = #{tinhTrangChuyen},
    ngayGioKhoiHanh = #{ngayGioKhoiHanh},
    ngayGioDen = #{ngayGioDen},
    chiPhiVanHanh = #{chiPhiVanHanh},
    tiLeThuLao = #{tiLeThuLao},
    maXe = #{maXe},
    maTuyen = #{maTuyen},
    maMua = #{maMua},
    maGiaVe = #{maGiaVe}
WHERE maChuyen = #{maChuyen}
and maTuyen = #{maTuyen} 
and maXe = #{maXe}

mapper.delete:
DELETE FROM ChuyenXe
WHERE maChuyen = #{maChuyen}
and maTuyen = #{maTuyen} 
and maXe = #{maXe}
